const input = $input.first().json;
function buildQs(obj) { return Object.entries(obj).filter(([k,v]) => v !== undefined && v !== null).map(([k,v]) => encodeURIComponent(k) + '=' + encodeURIComponent(String(v))).join('&'); }

const action = input.action || '';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.confluence&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;
if (!creds.atlassian_email || !creds.atlassian_api_token || !creds.atlassian_site) {
  return [{ json: { error: 'Confluence credentials not configured. Need atlassian_email, atlassian_api_token, atlassian_site. If Jira is installed, these are shared automatically.' } }];
}

const site = creds.atlassian_site.replace(/^https?:\/\//, '').replace(/\/$/, '');
const V2 = 'https://' + site + '/wiki/api/v2';
const V1 = 'https://' + site + '/wiki/rest/api';
const basic = Buffer.from(creds.atlassian_email + ':' + creds.atlassian_api_token).toString('base64');
const authHeaders = { 'Authorization': 'Basic ' + basic, 'Accept': 'application/json' };
const jsonHeaders = { ...authHeaders, 'Content-Type': 'application/json' };

function truncate(text, max) {
  max = max || 5000;
  if (text.length > max) return text.substring(0, max) + '\n\n... (truncated, ' + text.length + ' chars total)';
  return text;
}

function pageUrl(id) {
  return 'https://' + site + '/wiki/spaces/_/pages/' + id;
}

function stripHtml(html) {
  if (!html) return '';
  return String(html)
    .replace(/<br\s*\/?>(\n)?/gi, '\n')
    .replace(/<\/(p|h[1-6]|li|div)>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// === list_spaces ===
if (action === 'list_spaces') {
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/spaces?limit=100', headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No spaces found.' } }];
    let out = 'Spaces (' + items.length + '):\n';
    for (const s of items) {
      out += '  [' + s.id + '] ' + (s.key || '?') + ' — ' + (s.name || '') + ' (' + (s.type || 'space') + ')\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence list_spaces failed: ' + err.message } }];
  }

// === list_pages_in_space ===
} else if (action === 'list_pages_in_space') {
  const spaceId = input.space_id;
  if (!spaceId) return [{ json: { error: 'Parameter "space_id" is required (numeric id from list_spaces).' } }];
  const limit = Math.min(parseInt(input.limit) || 25, 100);
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/spaces/' + encodeURIComponent(spaceId) + '/pages?limit=' + limit, headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No pages in space ' + spaceId + '.' } }];
    let out = 'Pages in space ' + spaceId + ' (' + items.length + '):\n';
    for (const p of items) out += '  [' + p.id + '] ' + (p.title || '') + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence list_pages_in_space failed: ' + err.message } }];
  }

// === search_pages ===
} else if (action === 'search_pages') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Use CQL (e.g. \'text ~ "onboarding"\', \'space = MARKETING AND type = page\') or plain text (auto-wrapped as text~query).' } }];
  const limit = Math.min(parseInt(input.limit) || 10, 50);
  let cql = query;
  if (!/[=~]|\bAND\b|\bOR\b/i.test(cql)) cql = 'type = page AND text ~ "' + cql.replace(/"/g, '\\"') + '"';
  try {
    const qs = buildQs({ cql, limit: String(limit) });
    const r = await helpers.httpRequest({ method: 'GET', url: V1 + '/content/search?' + qs, headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No pages matched CQL: ' + cql + '. Note: Confluence search index may lag on newly created pages — try list_pages_in_space as fallback.' } }];
    let out = 'Pages matched (' + items.length + '):\n';
    for (const p of items) out += '  [' + p.id + '] ' + (p.title || '') + ' (' + (p.type || 'page') + ')\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence search_pages failed: ' + err.message } }];
  }

// === get_page ===
} else if (action === 'get_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/pages/' + encodeURIComponent(pageId) + '?body-format=storage', headers: authHeaders });
    let out = '**' + (r.title || '') + '** [id: ' + r.id + ']\n';
    if (r.spaceId) out += 'Space id: ' + r.spaceId + '\n';
    if (r.parentId) out += 'Parent id: ' + r.parentId + '\n';
    if (r.version) out += 'Version: ' + r.version.number + '\n';
    if (r.authorId) out += 'Author id: ' + r.authorId + '\n';
    if (r.createdAt) out += 'Created: ' + r.createdAt.substring(0, 10) + '\n';
    const body = r.body && r.body.storage ? r.body.storage.value : '';
    if (body) out += '\nBody:\n' + stripHtml(body) + '\n';
    out += '\n' + pageUrl(r.id);
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence get_page failed: ' + err.message } }];
  }

// === get_page_by_title ===
} else if (action === 'get_page_by_title') {
  const title = input.title;
  if (!title) return [{ json: { error: 'Parameter "title" is required (exact title, ASCII works best).' } }];
  const spaceId = input.space_id;
  try {
    let url = V2 + '/pages?title=' + encodeURIComponent(title);
    if (spaceId) url += '&space-id=' + encodeURIComponent(spaceId);
    const r = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No page with title "' + title + '"' + (spaceId ? ' in space ' + spaceId : '') + '. Titles with em-dashes or diacritics may not match — try search_pages instead.' } }];
    let out = 'Pages matching title "' + title + '" (' + items.length + '):\n';
    for (const p of items) out += '  [' + p.id + '] ' + (p.title || '') + ' (space: ' + (p.spaceId || '?') + ', v' + (p.version ? p.version.number : '?') + ')\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence get_page_by_title failed: ' + err.message } }];
  }

// === list_children ===
} else if (action === 'list_children') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  const limit = Math.min(parseInt(input.limit) || 25, 100);
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/pages/' + encodeURIComponent(pageId) + '/children?limit=' + limit, headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'Page ' + pageId + ' has no child pages.' } }];
    let out = 'Children of ' + pageId + ' (' + items.length + '):\n';
    for (const p of items) out += '  [' + p.id + '] ' + (p.title || '') + '\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence list_children failed: ' + err.message } }];
  }

// === create_page ===
} else if (action === 'create_page') {
  const spaceId = input.space_id;
  const title = input.title;
  const body = input.body;
  if (!spaceId) return [{ json: { error: 'Parameter "space_id" is required (numeric id from list_spaces).' } }];
  if (!title) return [{ json: { error: 'Parameter "title" is required.' } }];
  if (!body) return [{ json: { error: 'Parameter "body" is required (HTML in storage format, e.g. "<p>Hello</p>").' } }];
  const payload = {
    spaceId: String(spaceId),
    status: 'current',
    title: String(title),
    body: { representation: 'storage', value: String(body) }
  };
  if (input.parent_id) payload.parentId = String(input.parent_id);
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: V2 + '/pages', headers: jsonHeaders, body: JSON.stringify(payload) });
    return [{ json: { result: 'Page created [id: ' + r.id + ']: ' + r.title + '\n' + pageUrl(r.id) } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Confluence create_page failed: ' + msg } }];
  }

// === update_page ===
} else if (action === 'update_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  if (!input.title && !input.body) return [{ json: { error: 'Provide at least one of: title, body.' } }];
  try {
    const current = await helpers.httpRequest({ method: 'GET', url: V2 + '/pages/' + encodeURIComponent(pageId) + '?body-format=storage', headers: authHeaders });
    const nextVersion = (current.version && current.version.number ? current.version.number : 1) + 1;
    const payload = {
      id: String(pageId),
      status: 'current',
      title: input.title || current.title,
      body: { representation: 'storage', value: input.body || (current.body && current.body.storage ? current.body.storage.value : '') },
      version: { number: nextVersion }
    };
    const r = await helpers.httpRequest({ method: 'PUT', url: V2 + '/pages/' + encodeURIComponent(pageId), headers: jsonHeaders, body: JSON.stringify(payload) });
    return [{ json: { result: 'Page ' + pageId + ' updated to v' + nextVersion + ': ' + r.title + '\n' + pageUrl(pageId) } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Confluence update_page failed: ' + msg } }];
  }

// === delete_page ===
} else if (action === 'delete_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  try {
    await helpers.httpRequest({ method: 'DELETE', url: V2 + '/pages/' + encodeURIComponent(pageId), headers: authHeaders });
    return [{ json: { result: 'Page ' + pageId + ' deleted.' } }];
  } catch (err) {
    return [{ json: { error: 'Confluence delete_page failed: ' + err.message } }];
  }

// === add_comment_to_page ===
} else if (action === 'add_comment_to_page') {
  const pageId = input.page_id;
  const text = input.text;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  if (!text) return [{ json: { error: 'Parameter "text" is required.' } }];
  const value = /<[a-z][^>]*>/i.test(text) ? text : '<p>' + String(text).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;') + '</p>';
  const payload = {
    pageId: String(pageId),
    body: { representation: 'storage', value }
  };
  try {
    const r = await helpers.httpRequest({ method: 'POST', url: V2 + '/footer-comments', headers: jsonHeaders, body: JSON.stringify(payload) });
    return [{ json: { result: 'Comment added to page ' + pageId + ' (comment id: ' + r.id + ').' } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Confluence add_comment_to_page failed: ' + msg } }];
  }

// === list_comments_on_page ===
} else if (action === 'list_comments_on_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/pages/' + encodeURIComponent(pageId) + '/footer-comments?body-format=storage&limit=50', headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No comments on page ' + pageId + '.' } }];
    let out = 'Comments on page ' + pageId + ' (' + items.length + '):\n\n';
    for (const c of items) {
      const body = c.body && c.body.storage ? stripHtml(c.body.storage.value) : '';
      out += '  [' + c.id + '] ' + body + '\n';
    }
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence list_comments_on_page failed: ' + err.message } }];
  }

// === add_label_to_page ===
} else if (action === 'add_label_to_page') {
  const pageId = input.page_id;
  const label = input.label;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  if (!label) return [{ json: { error: 'Parameter "label" is required (e.g. "meeting-notes", "onboarding").' } }];
  const body = [{ prefix: 'global', name: String(label) }];
  try {
    await helpers.httpRequest({ method: 'POST', url: V1 + '/content/' + encodeURIComponent(pageId) + '/label', headers: jsonHeaders, body: JSON.stringify(body) });
    return [{ json: { result: 'Label "' + label + '" added to page ' + pageId + '.' } }];
  } catch (err) {
    const msg = err.response && err.response.body ? JSON.stringify(err.response.body) : err.message;
    return [{ json: { error: 'Confluence add_label_to_page failed: ' + msg } }];
  }

// === list_labels_on_page ===
} else if (action === 'list_labels_on_page') {
  const pageId = input.page_id;
  if (!pageId) return [{ json: { error: 'Parameter "page_id" is required.' } }];
  try {
    const r = await helpers.httpRequest({ method: 'GET', url: V2 + '/pages/' + encodeURIComponent(pageId) + '/labels', headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No labels on page ' + pageId + '.' } }];
    let out = 'Labels on page ' + pageId + ' (' + items.length + '):\n';
    for (const l of items) out += '  ' + (l.name || '') + ' (prefix: ' + (l.prefix || 'global') + ')\n';
    return [{ json: { result: out } }];
  } catch (err) {
    return [{ json: { error: 'Confluence list_labels_on_page failed: ' + err.message } }];
  }

// === search_by_label ===
} else if (action === 'search_by_label') {
  const label = input.label;
  if (!label) return [{ json: { error: 'Parameter "label" is required.' } }];
  const limit = Math.min(parseInt(input.limit) || 25, 100);
  const cql = 'label = "' + String(label).replace(/"/g, '\\"') + '"';
  try {
    const qs = buildQs({ cql, limit: String(limit) });
    const r = await helpers.httpRequest({ method: 'GET', url: V1 + '/content/search?' + qs, headers: authHeaders });
    const items = r.results || [];
    if (items.length === 0) return [{ json: { result: 'No content matched label "' + label + '". Note: search index may lag on newly labeled pages.' } }];
    let out = 'Content with label "' + label + '" (' + items.length + '):\n';
    for (const p of items) out += '  [' + p.id + '] ' + (p.title || '') + ' (' + (p.type || 'page') + ')\n';
    return [{ json: { result: truncate(out) } }];
  } catch (err) {
    return [{ json: { error: 'Confluence search_by_label failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_spaces, list_pages_in_space, search_pages, get_page, get_page_by_title, list_children, create_page, update_page, delete_page, add_comment_to_page, list_comments_on_page, add_label_to_page, list_labels_on_page, search_by_label.' } }];
}
